## Basic Parsing

```typescript
import { parseContent, parseContentAsync, TokenType } from '@konemono/nostr-content-parser';

const content = 'Hello npub1xyz... Check :custom_emoji: #nostr';
const tags = [['emoji', 'custom_emoji', 'https://example.com/emoji.png']];

// Synchronous parsing (recommended for most cases)
const tokens = parseContent(content, tags);
console.log(tokens);

// Asynchronous parsing with URL type detection
const tokensWithUrlTypes = await parseContentAsync(content, tags);
console.log(tokensWithUrlTypes);
```

## Working with Tokens

```typescript
// Filter by type
const nip19Tokens = tokens.filter(t => t.type === TokenType.NIP19);
const urlTokens = tokens.filter(t => t.type === 'url');

// Discriminated union (check token.type to narrow metadata type)
tokens.forEach(token => {
  if (token.type === 'url') {
    // Handle URL
  } else if (token.type === 'nip19') {
    // Handle NIP-19 reference
  } else if (token.type === TokenType.CUSTOM_EMOJI) {
    // Handle custom emoji
  } else {
    // Handle plain text
  }
});
```

## Rendering Custom Emojis

```typescript
// Custom emoji with emoji tag
const content = 'Hello :custom_emoji:';
const tags = [['emoji', 'custom_emoji', 'https://example.com/emoji.png']];
const tokens = parseContent(content, tags);

const emojiTokens = tokens.filter(t => t.type === TokenType.CUSTOM_EMOJI);

emojiTokens.forEach(token => {
  // token.content → ":custom_emoji:" (with colons)
  // token.metadata.name → "custom_emoji" (shortcode)
  // token.metadata.url → "https://example.com/emoji.png" (image URL)
  // token.metadata.hasMetadata → true (image metadata fetched)

  if (token.metadata.hasMetadata) {
    // Example: create <img> tag
    const img = document.createElement('img');
    img.src = token.metadata.url;
    img.alt = token.content;
    img.title = token.metadata.name;
    document.body.appendChild(img);
  }
});
```

